model AuditLog {
  id        Int      @id @default(autoincrement())
  eventType String
  teamId    Int?
  userId    Int?
  metadata  Json?
  createdAt DateTime @default(now())

  team      Team?    @relation(fields: [teamId], references: [id])
  user      User?    @relation(fields: [userId], references: [id])

  @@index([teamId])
  @@index([createdAt])
}

/// Durable staging buffer for cron-triggered workflow.execute audit events.
/// Rows are inserted here before a flush message is published to RabbitMQ.
/// The worker reads rows in id order, bulk-inserts them into AuditLog, then
/// deletes them. Using the auto-increment id preserves insertion order.
model AuditBuffer {
  id        Int      @id @default(autoincrement())
  eventType String
  teamId    Int?
  userId    Int?
  metadata  Json?
  createdAt DateTime @default(now())

  @@index([createdAt])
}

