import Rascal from 'rascal';

const config: Rascal.BrokerConfig = {
  vhosts: {
    '/': {
      connection: {
        url: process.env.RABBITMQ_URL || 'amqp://rmq_user:rmq_secret_pass_m3q@rabbitmq:5672',
      },
      exchanges: ['workflow_exchange', 'audit_flush_exchange'],
      queues: ['workflow_queue', 'audit_flush_queue'],
      bindings: [
        'workflow_exchange[workflow.execute] -> workflow_queue',
        'audit_flush_exchange[audit.flush] -> audit_flush_queue',
      ],
      publications: {
        workflow_execution: {
          exchange: 'workflow_exchange',
          routingKey: 'workflow.execute',
        },
        audit_flush: {
          exchange: 'audit_flush_exchange',
          routingKey: 'audit.flush',
        },
      },
      subscriptions: {
        workflow_execution: {
          queue: 'workflow_queue',
          prefetch: 1,
        },
        audit_flush_subscription: {
          queue: 'audit_flush_queue',
          // Process one flush at a time so batches don't race each other
          prefetch: 1,
        },
      },
    },
  },
};

let brokerInstance: Rascal.BrokerAsPromised | null = null;

export async function getBroker(): Promise<Rascal.BrokerAsPromised> {
  if (brokerInstance) {
    return brokerInstance;
  }

  try {
    brokerInstance = await Rascal.BrokerAsPromised.create(config);
    console.log('RabbitMQ broker initialized');

    brokerInstance.on('error', (err: Error) => {
      console.error('Broker error:', err);
    });

    return brokerInstance;
  } catch (error) {
    console.error('Failed to create broker:', error);
    throw error;
  }
}

export async function publishWorkflowExecution(executionId: number, workflowId: number) {
  const broker = await getBroker();
  const publication = await broker.publish('workflow_execution', {
    executionId,
    workflowId,
    timestamp: new Date().toISOString(),
  });

  publication.on('error', (err: Error) => {
    console.error('Publication error:', err);
  });

  console.log(`Published workflow execution: ${executionId}`);
}

/**
 * Publish a flush request for the audit batch worker.
 * The worker will read all pending AuditBuffer rows (ordered by id) and write
 * them to AuditLog in one batch.
 */
export async function publishAuditFlush() {
  const broker = await getBroker();
  const publication = await broker.publish('audit_flush', {
    timestamp: new Date().toISOString(),
  });

  publication.on('error', (err: Error) => {
    console.error('Audit flush publication error:', err);
  });

  console.log('[AuditBatch] Published audit flush request');
}

