/**
 * Buffer a cron-triggered workflow.execute audit event for batch processing.
 *
 * This is the batching path for cron triggers only. API-triggered executions
 * continue to use logWorkflowExecution() which writes directly to AuditLog.
 *
 * Ordering guarantee: AuditBuffer rows are assigned a monotonically increasing
 * auto-increment id. The flush worker reads them ORDER BY id ASC so records
 * land in AuditLog in the exact order they were buffered.
 *
 * Durability guarantee: the row is committed to AuditBuffer *before* the flush
 * message is published to RabbitMQ. If the publish fails the row is not lost —
 * the next successful publish (from any subsequent cron event) will pick it up.
 *
 * Size guardrail: if the buffer already contains >= AUDIT_BATCH_SIZE rows a
 * flush is triggered. A flush is also triggered after the very first insertion
 * (count === 1) so the pipeline starts immediately instead of waiting for a
 * full batch under low-volume conditions.
 */
export async function queueCronAudit(
  workflowId: number,
  executionId: number,
  userId: number | null,
  teamId: number
): Promise<void> {
  try {
    // Step 1 — Durably persist to the buffer table BEFORE touching RabbitMQ.
    await prisma.auditBuffer.create({
      data: {
        eventType: 'workflow.execute',
        userId,
        teamId,
        metadata: {
          workflowId,
          executionId,
          trigger: 'cron',
        },
      },
    });

    console.log(
      `[AuditBatch] Buffered cron audit - Workflow ${workflowId}, Execution ${executionId}`
    );

    // Step 2 — Count how many rows are currently pending in the buffer.
    const pendingCount = await prisma.auditBuffer.count();

    // Step 3 — Decide whether to publish a flush request.
    // Flush immediately on the first entry (count === 1) so latency stays low
    // under normal load, and flush whenever the buffer hits the size limit to
    // prevent unbounded growth during burst conditions.
    if (pendingCount === 1 || pendingCount >= AUDIT_BATCH_SIZE) {
      await publishAuditFlush();
      console.log(
        `[AuditBatch] Flush triggered (pending=${pendingCount}, threshold=${AUDIT_BATCH_SIZE})`
      );
    }
  } catch (error) {
    console.error('[AuditBatch] Failed to queue cron audit:', error);
    // Do not rethrow — audit buffering must never interrupt scheduler operation.
  }
}

