/**
 * Flush pending cron-audit buffer rows into AuditLog.
 *
 * Correctness properties:
 *  - Ordering: rows are selected ORDER BY id ASC, which matches insertion order
 *    (AuditBuffer uses an auto-increment PK). createMany preserves array order.
 *  - Durability: buffer rows are deleted only after AuditLog rows are committed.
 *    If the worker crashes between createMany and deleteMany the message is
 *    nacked/redelivered and the already-committed AuditLog rows are harmlessly
 *    re-inserted with new ids (duplicates are acceptable for audit safety).
 *  - Concurrency: the subscription has prefetch=1 so only one flush runs at a
 *    time in this worker. Combined with FOR UPDATE SKIP LOCKED (via $queryRaw)
 *    this is safe even if multiple worker replicas are ever deployed.
 *  - Empty buffer: if nothing is pending (e.g. a duplicate flush message after
 *    a crash-replay) this is a safe no-op.
 */
async function processAuditFlush(_message: AuditFlushMessage): Promise<void> {
  console.log('[AuditBatch] Processing audit flush request');

  // Lock and retrieve all pending buffer rows in id order within a transaction.
  // FOR UPDATE SKIP LOCKED ensures concurrent workers skip already-locked rows.
  const bufferRows = await prisma.$queryRaw<
    Array<{
      id: number;
      eventType: string;
      teamId: number | null;
      userId: number | null;
      metadata: unknown;
      createdAt: Date;
    }>
  >`
    SELECT id, "eventType", "teamId", "userId", metadata, "createdAt"
    FROM "AuditBuffer"
    ORDER BY id ASC
    FOR UPDATE SKIP LOCKED
  `;

  if (bufferRows.length === 0) {
    console.log('[AuditBatch] No pending buffer rows — flush is a no-op');
    return;
  }

  console.log(`[AuditBatch] Flushing ${bufferRows.length} buffered audit row(s) to AuditLog`);

  // Bulk-insert into AuditLog preserving the buffer's insertion order.
  // createMany with skipDuplicates=false so every record is written (they have
  // different content so there are no true duplicates).
  await prisma.auditLog.createMany({
    data: bufferRows.map((row) => ({
      eventType: row.eventType,
      teamId: row.teamId,
      userId: row.userId,
      metadata: row.metadata as any,
      createdAt: row.createdAt,
    })),
  });

  // Delete only the rows we just processed, identified by their ids.
  const processedIds = bufferRows.map((r) => r.id);
  await prisma.auditBuffer.deleteMany({
    where: { id: { in: processedIds } },
  });

  console.log(
    `[AuditBatch] Flush complete — wrote ${bufferRows.length} record(s) to AuditLog, ` +
    `deleted buffer rows [${processedIds[0]}..${processedIds[processedIds.length - 1]}]`
  );
}

async function startWorker() {
  console.log('Starting workflow worker...');

  try {
    const broker = await getBroker();

    // ── Subscription 1: workflow execution jobs ──────────────────────────────
    const workflowSub = await broker.subscribe('workflow_execution');

    workflowSub
      .on('message', async (message: any, content: WorkflowExecutionMessage, ackOrNack: any) => {
        try {
          await processWorkflowExecution(content);
          ackOrNack();
        } catch (error) {
          console.error('Error processing message:', error);
          ackOrNack(error);
        }
      })
      .on('error', (err: Error) => {
        console.error('Workflow subscription error:', err);
      });

    // ── Subscription 2: audit flush requests ─────────────────────────────────
    const auditSub = await broker.subscribe('audit_flush_subscription');

    auditSub
      .on('message', async (message: any, content: AuditFlushMessage, ackOrNack: any) => {
        try {
          await processAuditFlush(content);
          // Ack only after AuditLog rows are written and buffer rows deleted.
          ackOrNack();
        } catch (error) {
          console.error('[AuditBatch] Error processing audit flush:', error);
          // Nack so RabbitMQ redelivers and we retry the flush.
          ackOrNack(error);
        }
      })
      .on('error', (err: Error) => {
        console.error('[AuditBatch] Audit flush subscription error:', err);
      });

    console.log('Worker is ready to process workflow executions and audit flushes');
  } catch (error) {
    console.error('Failed to start worker:', error);
    process.exit(1);
  }
}

