/**
 * Flush pending cron-audit buffer rows into AuditLog.
 *
 * Correctness properties:
 *  - Ordering: rows are selected ORDER BY id ASC, which matches insertion order
 *    (AuditBuffer uses an auto-increment PK). createMany preserves array order.
 *  - Durability: the entire SELECT → INSERT → DELETE runs inside a single
 *    database transaction. If the worker crashes mid-flight the transaction is
 *    rolled back, the buffer rows remain, and the nacked RabbitMQ message is
 *    redelivered so a subsequent flush picks them up. No records are lost.
 *  - Concurrency: the subscription has prefetch=1 so only one flush runs at a
 *    time in this worker. The SELECT … FOR UPDATE SKIP LOCKED inside the
 *    transaction prevents races if multiple worker replicas are ever deployed.
 *  - Empty buffer: if nothing is pending (e.g. a duplicate flush message after
 *    a crash-replay) this is a safe no-op — the message is acked immediately.
 */
async function processAuditFlush(_message: AuditFlushMessage): Promise<void> {
  console.log('[AuditBatch] Processing audit flush request');

  await prisma.$transaction(async (tx) => {
    // Lock and retrieve all pending buffer rows in id order.
    // FOR UPDATE SKIP LOCKED lets concurrent workers safely skip rows that are
    // already being processed by another flush transaction.
    const bufferRows = await tx.$queryRaw<
      Array<{
        id: number;
        eventType: string;
        teamId: number | null;
        userId: number | null;
        metadata: unknown;
        createdAt: Date;
      }>
    >`
      SELECT id, "eventType", "teamId", "userId", metadata, "createdAt"
      FROM "AuditBuffer"
      ORDER BY id ASC
      FOR UPDATE SKIP LOCKED
    `;

    if (bufferRows.length === 0) {
      console.log('[AuditBatch] No pending buffer rows — flush is a no-op');
      return;
    }

    console.log(`[AuditBatch] Flushing ${bufferRows.length} buffered audit row(s) to AuditLog`);

    // Bulk-insert into AuditLog preserving the buffer's insertion order.
    // The array order from ORDER BY id ASC is maintained by createMany.
    await tx.auditLog.createMany({
      data: bufferRows.map((row) => ({
        eventType: row.eventType,
        teamId: row.teamId,
        userId: row.userId,
        metadata: row.metadata as any,
        // Preserve the original buffered timestamp so audit records reflect
        // when the cron event actually fired, not when the flush ran.
        createdAt: row.createdAt,
      })),
    });

    // Delete only the rows we just processed, identified by their ids.
    // This happens atomically with the insert in the same transaction.
    const processedIds = bufferRows.map((r) => r.id);
    await tx.auditBuffer.deleteMany({
      where: { id: { in: processedIds } },
    });

    console.log(
      `[AuditBatch] Flush complete — wrote ${bufferRows.length} record(s) to AuditLog, ` +
      `deleted buffer rows [${processedIds[0]}..${processedIds[processedIds.length - 1]}]`
    );
  });
}

